mapper.select:
SELECT written_date
  FROM diaries
 WHERE user_id = #{userId}
   AND deleted_at IS NULL
   AND analysis_status <> 'DRAFT'
   AND written_date >= #{monthStart}
   AND written_date < #{nextMonth}
 ORDER BY written_date

SELECT COALESCE(SUM(coin_delta) FILTER (WHERE coin_delta > 0), 0)::int AS coin_earned,
       COUNT(*) FILTER (WHERE event_type = 'RESOLUTION_SUCCESS')::int   AS resolution_success_count
  FROM character_events
 WHERE user_id = #{userId}
   AND created_at >= #{monthStart}
   AND created_at < #{nextMonth}

SELECT group_code
  FROM user_item_groups
 WHERE user_id = #{userId}
   AND acquired_at >= #{monthStart}
   AND acquired_at < #{nextMonth}
 ORDER BY acquired_at DESC
